import osimport sqlite3import tweepyimport prawfrom dotenv import load_dotenvload_dotenv()X_API_KEY = os.getenv("X_API_KEY")X_API_SECRET = os.getenv("X_API_SECRET")X_ACCESS_TOKEN = os.getenv("X_ACCESS_TOKEN")X_ACCESS_SECRET = os.getenv("X_ACCESS_SECRET")REDDIT_CLIENT_ID = os.getenv("REDDIT_CLIENT_ID")REDDIT_CLIENT_SECRET = os.getenv("REDDIT_CLIENT_SECRET")REDDIT_USERNAME = os.getenv("REDDIT_USERNAME")REDDIT_PASSWORD = os.getenv("REDDIT_PASSWORD")X_LIKE_THRESHOLD = 5X_IMPRESSION_THRESHOLD = 100REDDIT_SCORE_THRESHOLD = 10def audit_performance():    print("Initiating 24-Hour Analytics Audit...")    try:        conn = sqlite3.connect("apex_social.db")        c = conn.cursor()        c.execute("SELECT platform, post_id, content FROM posts ORDER BY timestamp DESC LIMIT 50")        posts = c.fetchall()    except sqlite3.OperationalError:        print("Social DB not found or empty. Skipping audit.")        return        winning_content = []    x_client = tweepy.Client(consumer_key=X_API_KEY, consumer_secret=X_API_SECRET, access_token=X_ACCESS_TOKEN, access_token_secret=X_ACCESS_SECRET) if X_API_KEY else None    reddit_client = praw.Reddit(client_id=REDDIT_CLIENT_ID, client_secret=REDDIT_CLIENT_SECRET, username=REDDIT_USERNAME, password=REDDIT_PASSWORD, user_agent="ApexGrowthEngine v1.0") if REDDIT_CLIENT_ID else None    for platform, post_id, content in posts:        try:            if platform == "X" and x_client:                tweet = x_client.get_tweet(id=post_id, tweet_fields=['public_metrics'])                if tweet.data:                    metrics = tweet.data.public_metrics                    if metrics['like_count'] >= X_LIKE_THRESHOLD or metrics['impression_count'] >= X_IMPRESSION_THRESHOLD:                        print(f"WINNING HOOK DETECTED [X]: {metrics['impression_count']} impressions, {metrics['like_count']} likes.")                        winning_content.append(content)                        elif platform == "Reddit" and reddit_client:                submission = reddit_client.submission(id=post_id)                if submission.score >= REDDIT_SCORE_THRESHOLD:                    print(f"WINNING HOOK DETECTED [Reddit]: Score of {submission.score}.")                    winning_content.append(content)                            except Exception as e:            print(f"Failed to fetch metrics for {platform} post {post_id}: {e}")    if winning_content:        with open("winning_hooks.txt", "a") as f:            for hook in set(winning_content):                f.write(f"\n---\n{hook}\n")        print("winning_hooks.txt updated. Agent training data enriched.")    else:        print("Audit complete. No new hooks crossed the viral threshold.")if __name__ == "__main__":    audit_performance()